var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"자기, 어째 걱정거리가 있어 보이는 얼굴이네?","JPN":"ダーリン、なんだか心配事がありそうな顔ね。","ENG":"Sweetie, you look like you're worried about something.","TWN":"親愛的，你怎麼一臉心事重重的樣子？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"여긴 참 이상한 술집이군.","JPN":"このバーは変だな。","ENG":"What a strange bar this is.","TWN":"這間酒吧真奇怪。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"사탕 달라고 졸라대는 꼬맹이에, 불온한 말투로 작업을 걸어오는 만취한 여자라니.","JPN":"キャンディをねだるチビに、不穏な口調でナンパをしてくる酔っ払いの女とは。","ENG":"There's a kid pestering for candy, and a drunk woman approaching me with a seditious tone for some reason.","TWN":"有跟我要糖的小鬼，還有爛醉的女人用危險的語氣跟我搭訕。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"얌전히 술만 마시는 것도 좋지만 그런 사나운 표정 짓고 있으면 손님들이 도망가요.","JPN":"大人しくお酒だけ飲んでるのもいいけど、そんな険しい顔をしてるとお客さんが逃げちゃうわ。","ENG":"It's nice to just sit and have a drink, but if you keep making that scary face, all the customers will run away.","TWN":"安靜喝酒是很好啦，但你臉那麼臭，客人都要被你嚇跑了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"흥, 그 원숭이. 여길 소개해준 건 결국 날 물 먹이려는 수작이었나?","JPN":"ふん、あのサル。ここを紹介してくれたのは、結局私を困らせるためだったのか？","ENG":"Hmph, that monkey. She introduced this place to me to give me the middle finger, didn't she?","TWN":"哼，那隻死猴子。介紹我來這裡，結果只想看我出糗嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"뭐야아? 지인소개로 온 거구나? 그럼 한잔 공짜로 만들어 줄게.","JPN":"何？　知り合いの紹介で来たのね。じゃあ、ただで1杯あげるわ。","ENG":"Oh? Did you come here by recommendation? Then I'll make you a drink on the house.","TWN":"唉呀？原來是朋友介紹的啊？那我請你喝一杯吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"당신… 주정뱅이가 아니라 이 가게 직원이었어?","JPN":"お前……酔っ払いではなくてこの店の職員だったのか？","ENG":"You're... not a drunk but an employee of this bar?","TWN":"你……不是醉鬼，而是這家店的員工？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"주정뱅이긴 하지만 일단은 점장이야. 그레모리 씨라고 부르면 돼.","JPN":"酔っ払いではあるけど、一応は店長よ。グレモリーさんでいいわ。","ENG":"I am a drunk, but I'm also the manager. Call me Gremory.","TWN":"雖然我也算醉鬼沒錯，但我是店長。叫我葛茉莉就好。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"본명은 아닌 걸 보니 숨기는 게 많은 모양이지?","JPN":"本名ではないな。隠し事が多いようだが。","ENG":"Seeing how it's not your real name, you must have a lot to hide, eh?","TWN":"名字也不是本名，看來你祕密不少嘛？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어머- 용한 분께서 손님으로 오셨네.","JPN":"あら。とても頭の切れるお客さんだったのね。","ENG":"Oh, my. Looks like we got ourselves a mind reader here.","TWN":"哎呀～厲害的客人上門了呢。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"…한잔하러 왔을 뿐이야. 딱히 당신에게 용무는 없어.","JPN":"……飲みに来ただけだ。別にお前に用はない。","ENG":"...I'm just here for a drink. I have no business for you.","TWN":"……我只是來喝一杯，沒打算找你麻煩。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그라운드원에 우리 가게만큼 값싸게 취하기 좋은 곳이 없긴 하지.","JPN":"グラウンド・ワンにうちの店ほど安くて飲みやすいところはないわね。","ENG":"There's not a bar in Ground One where you can get drunk as cheaply as ours.","TWN":"在G1買醉，沒有比我們店更便宜的地方了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"근데 그거 알아? 여기 무료로 사랑 점도 봐준다?","JPN":"でも、それ知ってる？　ここは無料で恋愛占いもしてくれるのよ。","ENG":"But did you know? We offer fortunetelling for free here.","TWN":"不過你知道嗎？我們這裡還免費幫人戀愛占卜喔？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"관심 없어.","JPN":"興味ない。","ENG":"Not interested.","TWN":"我沒興趣。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"정말? 고민이 있다면 얼마든지 들어줄 수도 있는데.","JPN":"本当に？　悩み事があったらいくらでも聞いてあげられるわ。","ENG":"Really? I'm all ears if you have any concerns you wish to talk about.","TWN":"真的嗎？如果你有煩惱，我也可以聽你說哦。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"처음보는 사람에게 내 사적인 이야길 털어놓는 취미는 없거든.","JPN":"初対面の人に自分のプライバシーを話す趣味はないからな。","ENG":"I'm not one to talk about my personal life to a stranger I just met.","TWN":"我可沒興趣跟第一次見面的人聊私事。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"자, 점장표 특제 칵테일 데몬 레이디야.","JPN":"はい。店長特製のカクテル、デーモンレディーよ。","ENG":"Here you go. The manager's special cocktail, Demon Lady.","TWN":"來，這杯是店長特製雞尾酒惡魔淑女。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"너무 독해서 쓰러질 지도 모르니 조심해.","JPN":"強くて倒れることになるかもしれないから気をつけなさい。","ENG":"It's strong, so be careful not to faint.","TWN":"這很烈，小心不要喝掛了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"흥, 날 뭘로 보고….","JPN":"ふん、私を何だと思って……","ENG":"Hmph. Who do you think I am?","TWN":"哼，你把我當成什麼……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"평소 관심있던 남자사람친구나 신경쓰이는 부하직원 한 명쯤 있지 않아?","JPN":"普段気にしている男の友だちとか、気になる部下とかが1人いたりしない？","ENG":"Don't you have a male friend or a subordinate that you care about?","TWN":"你平時難道沒有在意的男性朋友，或讓你掛心的部下嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"푸흡…! 콜록 콜록!","JPN":"ぷっ……！　ゲホ、ゲホ……！","ENG":"Pfft...! *Cough!* *Cough!*","TWN":"噗……！咳、咳咳！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_WATER"},{"id":"L27_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어머, 독하니까 조심하래도.","JPN":"あら、強いから気をつけなさいって言ったじゃない。","ENG":"See? I told you it's strong.","TWN":"哎呀，我不是說這很烈，要你小心點喝嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"당신이 느닷없이 이상한 소릴해서 그런 거야!","JPN":"お前がいきなり変なことを言うからだろう！","ENG":"This is because you started talking about nonsense!","TWN":"還不都是因為你突然說些奇怪的話害的！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"미안. 이제 찍소리 안하고 얌전히 있을게.","JPN":"ごめん。もう黙って大人しくしてるわね。","ENG":"Sorry, I won't say a word from now on.","TWN":"抱歉啦，我會乖乖閉嘴的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그렇게 빤히 쳐다보기만 할 거면, 차라리 하고 싶은 말을 하지 그래?","JPN":"そうやってじっと見ているようなら、いっそ言いたいことを言ったらどうだ？","ENG":"If you're going to keep staring at me like that, why don't you just say what you want to say?","TWN":"你要是只打算這樣盯著我看，倒不如直接說出你想說的話？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"역시 있는 거지? 신경 쓰이는 사람!","JPN":"やっぱりいるのね？　気になる人！","ENG":"So you do have someone you're interested in, right?!","TWN":"果然有吧？讓你在意的人！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L34_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"…있다면 어쩔 건데?","JPN":"……いたらどうする？","ENG":"...So what if I do?","TWN":"……就算有又怎樣？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"고민이 있으면 같이 터놓고 얘기나 해보자는 거야.","JPN":"悩みがある時には、人に打ち明けてみるのも良い手よ。","ENG":"I'm just saying that we could talk about our worries to each other.","TWN":"如果有煩惱，我們就敞開心扉聊聊嘛。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"같은 여자끼리 내숭떨 필요도 없잖아?","JPN":"同じ女同志、猫を被る必要もないじゃない？","ENG":"There's no need to be coy in girls' talk, right?","TWN":"同樣都是女人，沒什麼好害羞的吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그래? 당신 눈에는 내가 수다나 떠는 평범한 여자로 보이는 모양이지?","JPN":"そうか？　お前の目には私がおしゃべり好きの普通の女に見えるようだな。","ENG":"Oh really? So in your eyes, I look like an ordinary girl who likes to chat, hmm?","TWN":"是嗎？我看起來像是愛聊天的普通女人嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"평범하지 않으면 대화도 할 수 없는 거야?","JPN":"普通じゃないと会話もできないの？","ENG":"So ordinary people are the only ones allowed to have a chat?","TWN":"不是普通女人，就不能聊天了？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"내 경우는 그래. 당신도 나랑 너무 얽히려 하지 마. 괜히 다치기 싫으면 말이야.","JPN":"私の場合にはそうだ。お前も私にあまり関わらない方がいい。怪我したくないならな。","ENG":"In my case, yes. So don't try to get involved with me that much. Not unless you want to get hurt, that is.","TWN":"我就是這樣。不想受傷的話，別跟我牽扯太深。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어머- 함부로 사람을 가까이하지 않는 차가운 도시여자구나. 낭만적이다.","JPN":"あら。むやみに人に近づかない冷たい都会の女ね。ロマンチックだわ。","ENG":"Oh, my. You're like the cold city girl, who doesn't get close to people. How romantic.","TWN":"哎呀～原來你是不輕易讓人靠近的冷漠都會女子，真浪漫。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"거기서 독기만 조금 빼면 완전 인기 있을 타입인데. 아쉽네.","JPN":"そこですこし愛嬌があればすごくモテそうなタイプなのに。残念ね。","ENG":"If you could just be a bit less mean, you'd be pretty popular. What a shame.","TWN":"要是殺氣少一點，肯定很受歡迎，真可惜。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"다른 사람이 날 어떻게 보는지는 관심 없어.","JPN":"他人が私のことをどう見てるのかは興味ない。","ENG":"I'm not interested in how others perceive me.","TWN":"我不在乎別人怎麼看我。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"하지만 당신을 좋아하는 사람이 있다면, 그게 누군지 궁금하지 않아?","JPN":"でもアナタのことが好きな人がいたら、それは誰なのか知りたくない？","ENG":"But wouldn't you like to know if anyone has a crush on you?","TWN":"但要是有人喜歡你，你不會好奇是誰嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그런 건… 아직 생각할 때가 아닐 뿐이야.","JPN":"まだ……そんなことを考えている時ではないだけだ。","ENG":"I... just don't think it's time to think about that right now.","TWN":"現在不是時候……想那種事。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"…그게 누군데?","JPN":"……で、誰なんだ？","ENG":"...But who is it?","TWN":"……那個人是誰？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"흐음, 역시 궁금한 거구나? 요 깍쟁이-","JPN":"ふーん、やっぱり知りたいんだね。このこのー","ENG":"Hmm, so you *are* curious. You sly vixen.","TWN":"嗯～你果然還是很好奇嘛，機靈鬼。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"안 물어보면 계속 거기 있을 것 같아서 물어본 거다.","JPN":"聞かなかったらずっとそこにいると思って聞いたんだ。","ENG":"I only asked because it looked like you wouldn't leave unless I did.","TWN":"如果我不問，你大概會一直把話題繞在那裡，所以我才問的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"어차피 사랑 점이니, 운명의 점괘니 하는 건 재미삼아 하는 오락일 뿐이겠지.","JPN":"どうせ恋愛占いだの運命だの、面白半分での娯楽に過ぎないだろう。","ENG":"All fortune-telling, whether about love or fate, is purely for entertainment.","TWN":"反正什麼戀愛占卜、命運占卜，也只是好玩而已吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"맞아. 재미삼아 하는 거야.","JPN":"そう。面白半分なの。","ENG":"You're right. I just do it for fun.","TWN":"沒錯，就是玩玩而已。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그러니 자기가 생각하는 남자 이름 좀 알려 줄래? 점을 볼 때 필요하거든.","JPN":"だから、ダーリンが思っている男の名前を教えてくれない？　占いに必要なの。","ENG":"Anyway, can you tell me the name of the man you're thinking of? I need it to read your fortune.","TWN":"所以你心裡想的那個男人，名字告訴我吧？占卜的時候會用得到。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"어차피 오락인데, 굳이 그런 것까지 알려줘야 하나?","JPN":"どうせ娯楽なのに、そんなものまで教えないといけないのか？","ENG":"If it's just for fun, why would I have to tell you that?","TWN":"只是娛樂活動而已，有必要連這個都告訴你嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"여기 종이에 그 사람의 이니셜만 써줘도 돼.","JPN":"この紙にその人の頭文字だけ書いてくれてもいいわ。","ENG":"All you need to do is write his initials on this piece of paper.","TWN":"那你可以把那個人的名字縮寫寫在這張紙上就好。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L6_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"옆에는 자기 이름의 이니셜도 함께 써줘.","JPN":"隣にはダーリンの頭文字も一緒にね。","ENG":"And next to it, write your initials too.","TWN":"旁邊再寫上你的名字縮寫。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"이러면 되겠어?","JPN":"これでいいか？","ENG":"Will this do?","TWN":"這樣可以了吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"좋아. 이제 점을 한 번 쳐볼까?","JPN":"いいわ。じゃあ、占ってみようかしら。","ENG":"Perfect. Now let's see what your future holds.","TWN":"好，那我來算算看囉？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그래, 한 번 무슨 마술을 부릴지 두고 보자고.","JPN":"ああ、どんな魔術を見せてくれるか見てみようじゃないか。","ENG":"Okay, let's see what kind of magic you'll do.","TWN":"好啊，我倒要看看你會耍什麼花樣。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"자아- 이니셜들을 이렇게 이렇게 연결해서, 나온 숫자를 더해주면…","JPN":"さてと、頭文字をこうやって繋げて、そこから出た数字を足すと……","ENG":"Okay... If I connect both initials like this, then add the numbers together...","TWN":"來～把縮寫這樣連起來，再把數字加一加……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L13_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"뭐야? 그 애들 장난 같은 짓은?","JPN":"なんだ？　その子どもの遊びみたいなのは。","ENG":"Huh? What's this child's play?","TWN":"什麼？這不是小孩子的把戲嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"왜애? 이거 단순해 보여도 꽤 잘 들어맞는 편인데?","JPN":"何よ？　これ、単純に見えるけど結構当たるわよ？","ENG":"Oh, come on. It may look simple, but it's quite accurate.","TWN":"幹嘛？別看它簡單，結果還挺準的喔。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그래, 취한 여자의 주사에 기대를 걸다니… 내가 어리석었지.","JPN":"はあ……酔っ払いの酒癖に期待するなんて……私が愚かだったな。","ENG":"Sure. Can't believe I trusted the words of a drunkard... How foolish of me.","TWN":"呵，我居然會期待一個喝醉女人的胡言亂語……我也真蠢。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"상대방 쪽이 운이 좋네. 자기 같은 사람을 만나다니 말이야.","JPN":"相手の方が運がいいわね。ダーリンみたいな人に出会うなんて。","ENG":"The man's lucky. Because he met someone like you.","TWN":"能遇到像你這樣的人，對方運氣不錯呢。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L18_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"흥, 글쎄.","JPN":"ふん、さあな。","ENG":"Hmph, I dunno.","TWN":"哼，最好是。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"서로에 대한 신뢰가 아주 두텁다고 나왔어. 어지간한 친구 사이보다 낫네.","JPN":"お互いとても信頼してるって出たの。普通の友だち関係よりましね。","ENG":"It says that you two trust each other a lot, far exceeding that of an average acquaintance.","TWN":"我看到你們彼此之間的信任非常深厚，比一般朋友關係更好。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"입에 발린 뻔한 소리로군.","JPN":"綺麗事だな。","ENG":"What an obvious thing to say to draw people in.","TWN":"這只是冠冕堂皇的話而已。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"자기는 그 남자가 원하는 걸 이뤄주고 싶은 거지?","JPN":"ダーリンは、あの男の願いを叶えてあげたいんでしょう？","ENG":"You want to help make his vision come true, right?","TWN":"你想替那個男人實現他的願望吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"何……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그 남자는 자기를 전적으로 신뢰하고 있지만 그건 의지하는 거랑 달라.","JPN":"あの男はダーリンを信頼してるけど、それは頼ってることとは違う。","ENG":"Although he trusts you with his life, it's different from him relying on you.","TWN":"他是完全信任你沒錯，但那跟依賴是不一樣的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그 남자는 자기가 쓰러지더라도 돌아보지 않고 나아갈 거야.","JPN":"あの男はダーリンが倒れても振り返らずに進むはずだわ。","ENG":"Even if you fall, he'll continue moving forward without looking back.","TWN":"就算你倒下了，他也會頭也不回地繼續往前走。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그건 무정하기 때문이 아니야. 그게 그 남자의 숙명인 거지.","JPN":"それはつれない人だからじゃない。それがあの男の宿命なんだから。","ENG":"But that's not because he's heartless. That's just his destiny.","TWN":"這不是因為他無情，那就是他的宿命。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"당신… 정체가 뭐지?","JPN":"お前……何者だ？","ENG":"Who... are you?","TWN":"你……到底是什麼人？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"점 보는 취미를 가진 술집 주인.","JPN":"占いが趣味の、バーの店長。","ENG":"I'm just a bar owner who enjoys fortune-telling as a hobby.","TWN":"興趣是占卜的酒吧老闆。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그래서…","JPN":"で……","ENG":"So...","TWN":"那麼……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그 사람은 자기 숙명을 이뤄낼 수 있나?","JPN":"あの人は自分の宿命を果たすことができるのか？","ENG":"Will he fulfill his destiny?","TWN":"他能完成自己的宿命嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"과연 어떻게 될까? 나도 거기까진 몰라.","JPN":"どうでしょうね？　アタシもそこまではわからないわよ。","ENG":"Who knows? I can't see that far into the future.","TWN":"誰知道呢？那我也說不準。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"정해진 운명도, 시곗바늘 고장나듯 뒤엉키곤 하는 법이니까.","JPN":"決められた運命も、時計の針が壊れるように乱れたりするから。","ENG":"Because even preordained fates get tangled like a broken clock hand.","TWN":"即使是既定的命運，有時也會像壞掉的時鐘指針糾結錯亂。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"하지만 한 가지 확실한 건… 미래의 운명이 오늘의 자기를 바꿔주진 않는단 거야.","JPN":"でも、1つだけ確かなのは……未来の運命が今日のダーリンを変えてはくれないということ。","ENG":"But one thing's for sure... and it's that the fate of the future doesn't change who you are today.","TWN":"但有件事我可以確定……未來的命運，不會替今天的你改變。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그러니 자기가 어떤 운명에 처해 있건, 너무 쉽게 단념하진 마.","JPN":"だからダーリンがどんな運命にあっても、あんまり簡単には諦めないで。","ENG":"So no matter what fate you find yourself in, don't give up so easily.","TWN":"所以不管你面對什麼命運，都別太輕易放棄。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"내 말. 무슨 뜻인지 알지?","JPN":"アタシの言葉。わかるでしょう？","ENG":"Do you understand what I'm getting at?","TWN":"你懂我說的意思吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"역시 그레모리 씨는 굉장하시네요.","JPN":"やっぱりグレモリーさんはすごいですね。","ENG":"You really are amazing, Gremory.","TWN":"葛茉莉小姐果然很厲害呢。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"말수 적고 인상도 무섭던 손님께서 다시 들르겠다고 하셨어요.","JPN":"無口で怖い印象のお客様が、また来るって言ってました。","ENG":"Even that scary and quiet customer said she'll come back again.","TWN":"那位話不多、表情又嚇人的客人說下次還會再來。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그래? 다음번엔 남자친구라도 같이 데려오려나?","JPN":"そう？　今度は彼氏でも連れてくるのかしらね。","ENG":"Really? Maybe she'll come back with her boyfriend next time.","TWN":"是嗎？下次會不會連男朋友都一起帶來呢？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"연애 상담이었나 보네요?","JPN":"恋愛相談だったんですか？","ENG":"Did you give her some love advice?","TWN":"看來是戀愛諮詢啊？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…으음. 무슨 상담이었더라? 잘 기억이 안 나네?","JPN":"……うーん、何の相談だったかな。よく覚えていないわ。","ENG":"...Um. I'm not so sure. I can't remember.","TWN":"……嗯，我們聊了什麼？我有點記不清了？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그레모리 씨는 신기한 분이에요. 항상 술에 취해 인사불성인 사람처럼 굴지만…","JPN":"グレモリーさんは不思議な方です。いつも酔っぱらってる人のように行動してるけど……","ENG":"You're an enigma, Gremory. You always act like a drunk, but...","TWN":"葛茉莉小姐真的很神奇。雖然總是一副醉到不省人事的樣子……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"찾아오는 손님들에게 늘 도움이 되는 조언을 해주시잖아요?","JPN":"訪ねて来るお客様にはいつもためになるアドバイスをしてあげるじゃないですか。","ENG":"You always seem to give helpful advice to all your customers.","TWN":"卻總能給來訪的客人有幫助的建議。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그래서 존경스러워요.","JPN":"だから尊敬してるんです。","ENG":"That's what I respect about you.","TWN":"所以我很尊敬你。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"아아, 귀여운 우리 니콜 양. 날 그렇게 생각해주고 있었다니-","JPN":"ああ、可愛いニコルちゃん。アタシのことをそう思ってくれてたなんてー","ENG":"Aww, my adorable Nicole. I didn't know you thought of me like that.","TWN":"啊啊，我可愛的妮可小姐，原來你是這樣看我的啊～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그렇다고 뺨을 부비는 건 너무 어린 아이 취급 아닌가요?","JPN":"だからと言って頬をすりすりするのは子ども扱いじゃないですか？","ENG":"But don't you think you're treating me too much like a child by rubbing my cheek against yours?","TWN":"可、可是這樣用臉蹭我，不會太把我當小孩子了嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…어라?","JPN":"……あれ？","ENG":"...Huh?","TWN":"……咦？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"손님이 계시던 테이블에 웬 봉투가 있네요.","JPN":"お客様がいたテーブルに、封筒があります。","ENG":"There's an envelope on the table where she was sitting.","TWN":"客人坐過的桌子上，好像有個信封。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L7_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"봉투?","JPN":"封筒？","ENG":"An envelope?","TWN":"信封？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"복채… 라고 쓰여 있네요. 이게 무슨 뜻일까요?","JPN":"見料……って書いてありますね。これってどういうことでしょう？","ENG":"It says... \\"fortune fee\\"? What does that mean?","TWN":"寫著占卜費……這是什麼意思呢？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"고맙다는 표현인 것 같은데… 뭔가 엄청난 오해를 산 모양이네.","JPN":"ありがたいって意味なんだと思うけど……何かとんでもない誤解をしてるようね。","ENG":"I think she was trying to express her gratitude... But there seems to have been a huge misunderstanding.","TWN":"大概是表示感謝吧……看來我引起了很大的誤會了呢。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};